  ('real-estate-moex-02209', 'real-estate', 'real-estate-moex-099-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '下列有關不動產經紀營業員及不動產經紀營業員訓練之敘述，何者錯誤？', '["未領有不動產經紀營業員證明者不能充任不動產經紀營業員", "不動產經紀營業員經訓練後取得之證明，於辦理登錄後，其有效期間為3年", "不動產經紀營業員訓練證明有效期限期滿後，可檢附完成訓練20個小時以上之證明文件，向中央主管 機關指定之機構、團體重新辦理登錄", "不動產經紀營業員訓練不得少於30個小時"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:11+00:00", "source_pdf_sha1": "fd1783d600a7", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "099220", "c": "601", "s": "500", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "不動產經紀相關法規概要", "year": "099", "exam_name": "099年建築師、技師、不動產經紀人、記帳士考試", "original_question_number": 7, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
